class MusicianCareer:
    def __init__(self, name):
        self.name = name
        self.performances = []
        self.appointments = []

    def add_performance(self, city, year, event):
        self.performances.append((year, city, event))

    def add_appointment(self, city, year, title):
        self.appointments.append((year, city, title))

    def get_chronology(self):
        return sorted(self.performances + self.appointments, key=lambda x: x[0])

# Example usage for Cristofaro
cristofaro = MusicianCareer("Ferdinando de Cristofaro")
cristofaro.add_performance("Naples", 1860, "Conservatory Debut")
cristofaro.add_performance("Milan", 1881, "Composition Honors")
cristofaro.add_performance("London", 1881, "Conductor Appointment")
cristofaro.add_performance("Paris", 1882, "Premier Mandolinist Debut")
cristofaro.add_appointment("Paris", 1889, "Death")

print(cristofaro.get_chronology())
